export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "17:36。灣岸署。技術說明室。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "比物件確認室大一點。一張長桌。桌上有一台筆電。幾份列印文件。牆上有一面投影螢幕，沒有開。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌邊坐著一個男人。三十多歲。短髮。眼鏡。深色外套。眼下有很深的陰影。像好幾天沒有睡好。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺直樹。東都危機システム株式会社。公共安全系統部。技術協力人員。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他看起來不像黑衣人。像一個被叫來加班的工程師。眼下那圈黑是真的。不是演的。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦刑警站在桌邊。先對小野寺說明程序。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "這是供應商技術說明，不是鑑定。你只回答格式與產品用語。不對個案做判斷。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺點頭。動作很小。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警轉向澪。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "在妳同意下，我們只向他展示以下內容。去識別化的第二階段預約頁裁切圖。鏡背刮痕裁切照片與比例尺。不含姓名、住址、臉部及鏡子正面。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "同意。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警把筆電轉向小野寺。螢幕上是一張裁切圖。預約頁的右上角。只有那行代碼。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "G07／12。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺看了一眼。眼鏡後面的眼睛動了一下。很快。像讀到一個熟悉的東西。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺直樹", dialogue: "如果只看這串，它和我們同步產品的地址表記很像。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他認出來了。不到兩秒。G 開頭。兩位數。斜線。兩位數。他每天看這種東西。這是職業反射。不是驚訝。是辨認。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警追問。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "如果照你們的系統讀呢？", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺停了一下。像在確認自己要說什麼。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺直樹", dialogue: "G07 應該是第七同步群。斜線後的 12 是群內端點。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說完。立刻補了一句。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺直樹", dialogue: "我只能說表記相似。這不能證明它就是 TKS-SYNC 地址，也不能證明研究裡的 12 和設備端點是同一種東西。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯條件式。他每說一句就補一個限制。像在讀免責聲明。他不是在幫我。也不是在害我。他只是在做他的工作。然後在做的時候，發現自己可能碰到了不該碰的東西。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警把第二張照片推過去。鏡背刮痕裁切圖。帶比例尺。沒有正面。沒有臉。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺看了更久。眉頭皺了一下。又鬆開。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺直樹", dialogue: "這些筆畫可能是在抄同一串東西。但光靠這張照片，我不能把它完整讀出來。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他沒有說鏡背刻著 G07／12。他說的是「可能是在抄」。光靠照片不能完整讀出來。這是正確的。鏡背不能單獨還原那串字。他認的是預約頁。不是鏡子。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警指著螢幕上的代碼。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "端點是什麼？", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺直樹", dialogue: "同一則警報要同時出現在很多地方。螢幕、月台面板、廣播系統，都需要有自己的位置號。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說的時候語氣變平了。像在讀手冊。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "但這不是設備。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "刑警看了一眼桌上封袋裡的鏡子。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺直樹", dialogue: "所以我只能解釋字串格式。不能解釋它為什麼會出現在那份研究文件上。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在退。他在把自己縮回格式說明的範圍裡。他不碰「為什麼」。只碰「怎麼讀」。這是一個知道邊界在哪裡的工程師。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著他。他的手放在桌上。沒有動。指尖微微蜷起來。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯現在。放一小段出去。看我說了之後他變成什麼。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "TKS 也出現在那份睡眠研究文件的頁尾。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音不大。房間很安靜。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺的反應很小。他沒有抬頭。他第二次看向螢幕上的預約頁裁切圖。看了一秒。然後轉回來。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺直樹", dialogue: "那份研究的公開名稱是什麼？", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不確定這裡適合說。那是兒少研究的頁尾標記。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他點了一下頭。像在確認自己不該追問。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺直樹", dialogue: "教育資料服務部和我們公共安全系統部分開運作。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺直樹", dialogue: "公司不同部門有時候會共用版號與表記規範。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.OnoderaNaoki, character: "小野寺直樹", dialogue: "設定檔名稱和群組映射會隨版本更新。現行手冊不一定等於事件當晚的配置。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.OnoderaNaoki_Guarded },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在解釋。不是在暗示。他說的是任何維護系統的工程師都會知道的事。版本會變。設定檔會換。手冊不一定反映當晚的配置。這不是祕密提示。這只是普通技術說明。可是——", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯可是「版本更新」這四個字留在我腦裡。如果現行手冊不一定等於當晚配置。那麼舊版本裡，會不會有現行版已經刪掉的東西？", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有把這個想法說出口。她只是把它記下來。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "18:02。刑警把筆電收回。螢幕暗掉。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "今天的供應商技術說明到此。你的說法會記為供應商技術說明，不是獨立鑑定。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小野寺點頭。站起來。把外套拉了一下。他沒有看澪。也沒有看鏡子。他看著桌面。像在確認自己沒有留下任何不該留下的東西。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走出去了。門關上。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間裡只剩澪和刑警。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪翻開私人筆記。找到空白頁。她畫了一個表格。三列。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一列。她寫——", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "睡眠研究。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "旁邊寫——", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "個體 12？", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "問號。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二列。她寫——", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "警報語法。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "旁邊寫——", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "端點 12？", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "問號。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三列。她寫——", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "真正的人。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "旁邊寫——", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "朝倉悠真。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有問號。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯同一個 12。在睡眠研究裡，它叫個體。在警報語法裡，它叫端點。在第三列，它叫朝倉悠真。三個名字。同一個數字。我不能證明它們在說同一件事。可是我第一次覺得——", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯兩套制度都比她更早替悠真決定了他是什麼。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那三列。兩個問號。一個名字。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "研究文件把他分成個體。警報產品把他讀成端點。她把他寫回人。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "可是她不知道那兩個問號什麼時候會變成句號。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不能證明。不能畫等號。個體和端點未必是同一種東西。格式相似不是來源證明。小野寺自己說了。我只能說表記相似。這不能證明。可是——", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯可是那個 12。它出現在兩個地方。一個是兒少研究頁。一個是公共警報產品。同一家公司。同一種格式。同一個數字。我不能說它們相同。但我可以記住它們並排在那裡的樣子。", background: Background.Chapter_13_Ch13_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她合上筆記本。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "18:08。她站起來。背上背包。鏡子在她背後。筆記在她手裡。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走出技術說明室。走廊還是很長。日光燈還是很白。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她知道接下來還有物件返還確認。還有承辦人讀回她的陳述。還有她能確認的，和她拿不到的。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她腦裡現在只有那三列。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "個體 12？端點 12？朝倉悠真。", background: Background.Chapter_13_Ch13_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩套制度都比她更早替她弟弟決定了他是什麼。而她能做的，只是在第三列寫回他的名字。", background: Background.Chapter_13_Ch13_Act3_S0 },
];
